import java.io.*;
import org.owasp.encoder.Encode;

public class XSSSecureCode {
    public static void main(String[] args) {
        try {
            BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));
            System.out.print("Enter your name: ");
            String name = reader.readLine();

            // Sanitize and encode user input before outputting it to the webpage
            String sanitizedName = Encode.forHtml(name);
            System.out.println("<p>Welcome, " + sanitizedName + "!</p>");
        } catch (IOException e) {
            System.err.println("Error reading input");
        }
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
